fn main() {
    let greeting = "Hello";
    let greeting = String::from(greeting);
    let greeting = greeting.to_uppercase();
    println!("{}", greeting);  // HELLO

    // Shadowing with type change
    let value = "42";
    let value: i32 = value.parse().unwrap();
    println!("Value doubled: {}", value * 2);
}
